import { expect, test, describe } from "vitest";
import { MoonshineSymmetrySieve } from "../moonshine-symmetry-sieve";

describe("Moonshine-Symmetry Sieve — Cross-Modal Convergence", () => {
  test("isAligned detects shared McKay heartbeat", () => {
    expect(MoonshineSymmetrySieve.isAligned(1.1, 0.9)).toBe(true);
    expect(MoonshineSymmetrySieve.isAligned(2.0, 1.0)).toBe(false);
  });

  test("crossModalDeblur uses one modality to sharpen the other", () => {
    const blurredVideo = 0.4;
    const cleanAudio = 1.0; // Audio carries the Bule heartbeat
    
    const resolvedVideo = MoonshineSymmetrySieve.crossModalDeblur(blurredVideo, cleanAudio);
    
    expect(resolvedVideo).toBeGreaterThan(0.4);
    expect(resolvedVideo).toBe(0.7); // (0.4 + 1.0) / 2
  });
});
